mapper.select:
/* [SQL_ID:AuthorityMapper.selectList]*/ SELECT ROW_NUMBER() OVER() AS RN , COUNT(1) OVER() AS TOTAL_COUNT , A.* FROM ( SELECT A.AUTHORITY_ID , A.AUTHORITY_NAME , A.AUTHORITY_TYPE , A.DESCRIPTION , A.CREATED_BY , TO_CHAR(A.CREATED_AT, 'YYYY-MM-DD HH24:MI') AS CREATED_AT FROM SYS_AUTHORITY A
AND (A.AUTHORITY_ID LIKE '%' || #{searchText} || '%' OR A.AUTHORITY_NAME LIKE '%' || #{searchText} || '%')
AND A.AUTHORITY_ID LIKE '%' || #{searchText} || '%'
AND A.AUTHORITY_NAME LIKE '%' || #{searchText} || '%'
ORDER BY A.AUTHORITY_TYPE ASC, A.AUTHORITY_ID ASC ) A
LIMIT #{pageSize} OFFSET #{offset}

mapper.insert:
/* [SQL_ID:AuthorityMapper.insert]*/
INSERT INTO SYS_AUTHORITY (
      AUTHORITY_ID
    , AUTHORITY_NAME
    , AUTHORITY_TYPE
    , DESCRIPTION
    , CREATED_BY
) VALUES (
      #{authorityId}
    , #{authorityName}
    , #{authorityType}
    , #{description}
    , #{createdBy}
 )

mapper.update:
/* [SQL_ID:AuthorityMapper.update]*/
UPDATE SYS_AUTHORITY

      AUTHORITY_NAME     = #{authorityName}
    , AUTHORITY_TYPE  = #{authorityType}
    , DESCRIPTION  = #{description}
    , UPDATED_BY       = #{updatedBy}
    , UPDATED_AT      = NOW()


    AND AUTHORITY_ID   = #{authorityId}
